"""Reality signal computation from search results."""

from __future__ import annotations


def compute_signal(
    repos: list[dict],
    hn_posts: list[dict],
) -> dict:
    """Compute a 0-100 reality signal from search results.

    Returns a dict with score, verdict, and breakdown.
    """
    # GitHub component (0-60)
    total_repos = len(repos)
    max_stars = max((r["stars"] for r in repos), default=0)

    if total_repos == 0:
        gh_score = 0
    elif total_repos <= 3:
        gh_score = 15
    elif total_repos <= 7:
        gh_score = 30
    else:
        gh_score = 45

    if max_stars >= 5000:
        gh_score = min(60, gh_score + 20)
    elif max_stars >= 1000:
        gh_score = min(60, gh_score + 15)
    elif max_stars >= 100:
        gh_score = min(60, gh_score + 10)

    # HN component (0-40)
    total_hn = len(hn_posts)
    max_points = max((p["points"] for p in hn_posts), default=0)

    if total_hn == 0:
        hn_score = 0
    elif total_hn <= 2:
        hn_score = 10
    else:
        hn_score = 25

    if max_points >= 100:
        hn_score = min(40, hn_score + 15)
    elif max_points >= 30:
        hn_score = min(40, hn_score + 10)

    score = min(100, gh_score + hn_score)

    if score < 30:
        verdict = "LOW"
    elif score <= 60:
        verdict = "MODERATE"
    else:
        verdict = "HIGH"

    return {
        "score": score,
        "verdict": verdict,
        "breakdown": {
            "github": gh_score,
            "hn": hn_score,
        },
    }

"""CLI entry point for priorart."""

from __future__ import annotations

from typing import Annotated

import typer

from priorart.formatters import format_json, format_markdown, format_table
from priorart.scanner import scan

app = typer.Typer(
    name="priorart",
    help="Scan GitHub and Hacker News for prior art on an idea.",
    add_completion=False,
)


@app.callback(invoke_without_command=True)
def main(ctx: typer.Context) -> None:
    """Prior art scanner — search GitHub and HN for existing solutions."""
    if ctx.invoked_subcommand is None:
        typer.echo(ctx.get_help())
        raise typer.Exit()


@app.command("scan")
def scan_cmd(
    idea: Annotated[str, typer.Argument(help="Idea description to scan")],
    format: Annotated[
        str,
        typer.Option(
            "--format",
            "-f",
            help="Output format: json, markdown, or table",
        ),
    ] = "table",
    sources: Annotated[
        str,
        typer.Option(
            "--sources",
            "-s",
            help="Comma-separated sources to query (github,hn)",
        ),
    ] = "github,hn",
    github_token: Annotated[
        str | None,
        typer.Option(
            "--github-token",
            envvar="GITHUB_TOKEN",
            help="GitHub personal access token (or set GITHUB_TOKEN env var)",
            show_default=False,
        ),
    ] = None,
) -> None:
    """Scan for prior art on an idea."""
    fmt = format.lower().strip()
    if fmt not in ("json", "markdown", "table"):
        typer.echo(
            f"Error: invalid format '{fmt}'. Choose from: json, markdown, table",
            err=True,
        )
        raise typer.Exit(code=1)

    source_list = [s.strip().lower() for s in sources.split(",") if s.strip()]
    for s in source_list:
        if s not in ("github", "hn"):
            typer.echo(
                f"Error: unknown source '{s}'. Choose from: github, hn",
                err=True,
            )
            raise typer.Exit(code=1)

    if "github" in source_list and not github_token:
        typer.echo(
            "Note: No GITHUB_TOKEN set. GitHub search will work but is "
            "rate-limited (10 req/min). Set GITHUB_TOKEN for higher limits.",
            err=True,
        )

    result = scan(idea, github_token=github_token, sources=source_list)

    if fmt == "json":
        typer.echo(format_json(result))
    elif fmt == "markdown":
        typer.echo(format_markdown(result))
    else:
        typer.echo(format_table(result))


if __name__ == "__main__":
    app()

"""Tests for formatters module."""

import json

from priorart.formatters import format_json, format_markdown, format_table

SAMPLE_RESULT = {
    "query": "AI personal finance tracker",
    "queries": ["AI personal finance tracker", "AI personal finance"],
    "sources": [
        {
            "type": "github",
            "results": [
                {
                    "name": "org/finance-ai",
                    "stars": 1234,
                    "description": "AI-powered finance tracker",
                    "url": "https://github.com/org/finance-ai",
                    "updated": "2024-01-01",
                    "language": "Python",
                },
            ],
        },
        {
            "type": "hn",
            "results": [
                {
                    "title": "Ask HN: Best AI finance tools?",
                    "points": 42,
                    "comments": 17,
                    "url": "https://news.ycombinator.com/item?id=12345",
                    "date": "2024-03-01",
                },
            ],
        },
    ],
    "signal": {
        "score": 45,
        "verdict": "MODERATE",
        "breakdown": {"github": 30, "hn": 15},
    },
    "meta": {
        "timestamp": "2026-03-07T00:00:00+00:00",
        "version": "0.1.0",
    },
}

EMPTY_RESULT = {
    "query": "totally obscure niche idea",
    "queries": ["totally obscure niche idea"],
    "sources": [
        {"type": "github", "results": []},
        {"type": "hn", "results": []},
    ],
    "signal": {"score": 0, "verdict": "LOW", "breakdown": {"github": 0, "hn": 0}},
    "meta": {"timestamp": "2026-03-07T00:00:00+00:00", "version": "0.1.0"},
}


class TestFormatJson:
    def test_returns_valid_json(self):
        output = format_json(SAMPLE_RESULT)
        parsed = json.loads(output)
        assert parsed["query"] == "AI personal finance tracker"

    def test_json_has_required_keys(self):
        parsed = json.loads(format_json(SAMPLE_RESULT))
        assert "query" in parsed
        assert "sources" in parsed
        assert "signal" in parsed
        assert "meta" in parsed

    def test_signal_structure(self):
        parsed = json.loads(format_json(SAMPLE_RESULT))
        signal = parsed["signal"]
        assert "score" in signal
        assert "verdict" in signal
        assert "breakdown" in signal

    def test_empty_results_valid_json(self):
        output = format_json(EMPTY_RESULT)
        parsed = json.loads(output)
        assert parsed["signal"]["score"] == 0


class TestFormatMarkdown:
    def test_contains_header(self):
        output = format_markdown(SAMPLE_RESULT)
        assert "## 🔍 Prior Art Scan" in output

    def test_contains_signal(self):
        output = format_markdown(SAMPLE_RESULT)
        assert "45/100" in output

    def test_contains_verdict_moderate(self):
        output = format_markdown(SAMPLE_RESULT)
        assert "MODERATE" in output

    def test_contains_github_section(self):
        output = format_markdown(SAMPLE_RESULT)
        assert "### GitHub Repositories" in output
        assert "org/finance-ai" in output

    def test_contains_hn_section(self):
        output = format_markdown(SAMPLE_RESULT)
        assert "### Hacker News Discussions" in output
        assert "Ask HN: Best AI finance tools?" in output

    def test_empty_shows_no_results_message(self):
        output = format_markdown(EMPTY_RESULT)
        assert "No relevant repositories found." in output
        assert "No relevant discussions found." in output

    def test_pipe_in_description_escaped(self):
        result = {
            **SAMPLE_RESULT,
            "sources": [
                {
                    "type": "github",
                    "results": [
                        {
                            "name": "org/repo",
                            "stars": 100,
                            "description": "A | B tool",
                            "url": "https://github.com/org/repo",
                            "updated": "2024-01-01",
                            "language": "Python",
                        }
                    ],
                },
                {"type": "hn", "results": []},
            ],
        }
        output = format_markdown(result)
        assert "A \\| B tool" in output

    def test_low_verdict_label(self):
        output = format_markdown(EMPTY_RESULT)
        assert "🟢 LOW" in output

    def test_high_verdict_label(self):
        high_result = {
            **SAMPLE_RESULT,
            "signal": {
                "score": 75,
                "verdict": "HIGH",
                "breakdown": {"github": 60, "hn": 15},
            },
        }
        output = format_markdown(high_result)
        assert "🔴 HIGH" in output


class TestFormatTable:
    def test_contains_title(self):
        output = format_table(SAMPLE_RESULT)
        assert "Prior Art Scan" in output

    def test_contains_signal(self):
        output = format_table(SAMPLE_RESULT)
        assert "45/100" in output
        assert "MODERATE" in output

    def test_contains_github_section(self):
        output = format_table(SAMPLE_RESULT)
        assert "GitHub Repositories" in output
        assert "org/finance-ai" in output

    def test_contains_hn_section(self):
        output = format_table(SAMPLE_RESULT)
        assert "Hacker News Discussions" in output
        assert "Ask HN" in output

    def test_empty_shows_no_results(self):
        output = format_table(EMPTY_RESULT)
        assert "No relevant repositories found." in output
        assert "No relevant discussions found." in output

    def test_star_count_comma_formatted(self):
        output = format_table(SAMPLE_RESULT)
        assert "1,234" in output

    def test_shows_hn_url(self):
        output = format_table(SAMPLE_RESULT)
        assert "https://news.ycombinator.com/item?id=12345" in output

    def test_shows_queries(self):
        output = format_table(SAMPLE_RESULT)
        assert "AI personal finance tracker" in output


# ---------------------------------------------------------------------------
# Additional cross-format edge cases
# ---------------------------------------------------------------------------


class TestFormatJsonEdgeCases:
    def test_output_is_pretty_printed(self):
        output = format_json(SAMPLE_RESULT)
        # Pretty-printed JSON has newlines and indentation
        assert "\n" in output
        assert "  " in output

    def test_preserves_all_source_types(self):
        parsed = __import__("json").loads(format_json(SAMPLE_RESULT))
        types = [s["type"] for s in parsed["sources"]]
        assert "github" in types
        assert "hn" in types


class TestFormatMarkdownEdgeCases:
    def test_shows_queries_in_output(self):
        output = format_markdown(SAMPLE_RESULT)
        # Queries listed with backtick formatting
        assert "`AI personal finance tracker`" in output

    def test_caps_repos_at_8_rows(self):
        many_repos = [
            {
                "name": f"org/repo{i}",
                "stars": 100 - i,
                "description": f"Repo {i}",
                "url": f"https://github.com/org/repo{i}",
                "updated": "2024-01-01",
                "language": "Python",
            }
            for i in range(9)
        ]
        result = {
            **SAMPLE_RESULT,
            "sources": [
                {"type": "github", "results": many_repos},
                {"type": "hn", "results": []},
            ],
        }
        output = format_markdown(result)
        # Only first 8 repos should appear; repo8 should NOT
        assert "org/repo7" in output
        assert "org/repo8" not in output

    def test_hn_shows_points_and_comments(self):
        output = format_markdown(SAMPLE_RESULT)
        assert "42 pts" in output
        assert "17 comments" in output

    def test_moderate_verdict_label(self):
        output = format_markdown(SAMPLE_RESULT)
        assert "🟡 MODERATE" in output

